import fetch from"node-fetch";import{writePythonIcon}from"./write-python-icon.js";import{STUB_PATH_PYTHON}from"../utils/stub-path.js";const BULK_URL="https://ppicons.tsnc.tech/icons?icon=all";export async function generateAllPythonIcons(t,o=!1){const n=await fetch(BULK_URL);if(!n.ok)throw new Error(`Could not fetch list: ${n.statusText} – ${BULK_URL}`);const e=await n.json();console.log(`➡  Received ${e.length} icons. Generating Python components...`);const s=[],c=[];let i=[];for(const n of e){const e=writePythonIcon(n,t,STUB_PATH_PYTHON,o).then(t=>s.push(t)).catch(t=>c.push(`${n.name}: ${t.message}`));i.push(e),i.length>=10&&(await Promise.allSettled(i),i=[])}return await Promise.allSettled(i),{ok:s,fail:c}}